const DEFAULT_CONFIG = {
  cardOrder: [1, 2, 3, 4],
  navPriority: ['cta', 'about', 'features', 'blog'],
  heroStyle: 'immersive',
  colorMood: 'energetic',
  wobblyIntensity: 0.6,
};

const allowedHero = new Set(['minimal', 'immersive', 'compact']);
const allowedMood = new Set(['calm', 'energetic', 'focused']);
const allowedNav = new Set(['cta', 'about', 'features', 'blog']);
const allowedCards = new Set([1, 2, 3, 4]);

function sanitize(input) {
  const cfg = { ...DEFAULT_CONFIG };
  const errors = [];

  if (Array.isArray(input.cardOrder) && input.cardOrder.length === 4) {
    const cards = input.cardOrder.map((x) => Number(x));
    if (cards.every(Number.isFinite) && cards.every((x) => allowedCards.has(x)) && new Set(cards).size === 4) {
      cfg.cardOrder = cards;
    } else {
      errors.push('invalid cardOrder');
    }
  } else {
    errors.push('missing cardOrder');
  }

  if (Array.isArray(input.navPriority) && input.navPriority.length === 4) {
    const nav = input.navPriority.map((x) => String(x));
    if (nav.every((x) => allowedNav.has(x)) && new Set(nav).size === 4) {
      cfg.navPriority = nav;
    } else {
      errors.push('invalid navPriority');
    }
  } else {
    errors.push('missing navPriority');
  }

  if (allowedHero.has(String(input.heroStyle))) cfg.heroStyle = String(input.heroStyle);
  else errors.push('invalid heroStyle');

  if (allowedMood.has(String(input.colorMood))) cfg.colorMood = String(input.colorMood);
  else errors.push('invalid colorMood');

  const w = Number(input.wobblyIntensity);
  if (Number.isFinite(w) && w >= 0 && w <= 1) cfg.wobblyIntensity = Number(w.toFixed(2));
  else errors.push('invalid wobblyIntensity');

  return { cfg, errors };
}

const ipHash = $('Get Unclassified Sessions').item.json.ip_hash;
let source = 'gemini';
let raw = '';
let parsed = null;

try {
  raw = $input.item.json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const jsonStr = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(jsonStr);
} catch (err) {
  source = 'fallback';
}

const { cfg, errors } = sanitize(parsed || {});
if (errors.length > 0) source = 'fallback';

return [{
  json: {
    ...cfg,
    ip_hash: ipHash,
    policy_source: source,
    validation_errors: errors,
    raw_model_output: raw,
  },
}];
